            <div class="btn r" onclick="stopT()"><span class="bi"><svg viewBox="0 0 24 24" fill="currentColor" stroke="none"><rect x="4" y="4" width="16" height="16" rx="2.5"/></svg></span><span class="bl">إيقاف</span></div>
